solution_code:
#include <iostream>
#include <sstream>
#include <string>
#include <iomanip>

int main() {
    std::string line;
    std::getline(std::cin, line);

    std::istringstream iss(line);
    std::string name;
    int count = 0;
    double avg = 0.0;
    iss >> name >> count >> avg;

    std::cout << name << " scored " << count
              << " with avg "
              << std::fixed << std::setprecision(2) << avg << "\n";
    return 0;
}

