solution_code:
#include <iostream>
#include <sstream>
#include <string>
#include <iomanip>

std::string makeLabel(const std::string& key, int value) {
    std::ostringstream oss;
    oss << key << "=" << std::setfill('0') << std::setw(4) << value;
    return oss.str();
}

int main() {
    std::string key;
    int value;
    std::cin >> key >> value;
    std::cout << makeLabel(key, value) << "\n";
    return 0;
}
